code = """import pandas as pd
import json

review_counts_df = pd.DataFrame(locals()['var_function-call-16601361821216040979'])
business_info_df = pd.DataFrame(locals()['var_function-call-3247965914215238097'])

merged_df = pd.merge(review_counts_df, business_info_df, on='business_id', how='inner')

def extract_categories(description):
    if not description:
        return []
    # Categories are typically listed after phrases like 'offers services in', 'establishment offers a range of services including', 'in the categories of', etc.
    # Or sometimes they are just comma separated after some location info
    parts = description.split(' in the fields of ')
    if len(parts) > 1:
        categories_str = parts[1]
    else:
        parts = description.split(' offers a range of services in ')
        if len(parts) > 1:
            categories_str = parts[1]
        else:
            parts = description.split(' services including ')
            if len(parts) > 1:
                categories_str = parts[1]
            else:
                parts = description.split(' delightful array of dishes in the category of ')
                if len(parts) > 1:
                    categories_str = parts[1]
                else:
                    parts = description.split(' seeking ')
                    if len(parts) > 1:
                        categories_str = parts[1]
                    else:
                        # If no specific phrase, try to find comma separated list at the end
                        last_part = description.split(', ')[-1]
                        if last_part and ' & ' in last_part:
                            categories_str = last_part
                        elif last_part and ' and ' in last_part:
                            categories_str = last_part
                        else:
                            categories_str = description.split(', ')[-1]

    categories = [cat.strip() for cat in categories_str.replace('.', '').replace('and ', '').replace('/', ', ').replace(' & ', ', ').split(', ') if cat.strip()]
    return categories

merged_df['categories'] = merged_df['description'].apply(extract_categories)

# Explode the categories into separate rows
exploded_df = merged_df.explode('categories')

# Group by category and sum review counts
category_review_counts = exploded_df.groupby('categories')['review_count'].sum().reset_index()
category_review_counts = category_review_counts.sort_values(by='review_count', ascending=False)

top_5_categories = category_review_counts.head(5)

print('__RESULT__:')
print(top_5_categories.to_json(orient='records'))"""

